import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const projectRoot = path.resolve(__dirname, "..");
const dashboardDir = path.join(projectRoot, "standalone-effort-dashboard");

const sourceFiles = [
  "dashboard-utils.js",
  "dashboard-metrics.js",
  "dashboard-render.js",
  "app.js",
];

function stripModuleSyntax(source) {
  return source
    .replace(/import\s*\{[\s\S]*?\}\s*from\s*["'][^"']+["'];?\r?\n/g, "")
    .replace(/^export\s+/gm, "")
    .trim();
}

async function buildBundle() {
  const parts = await Promise.all(
    sourceFiles.map(async (fileName) => {
      const filePath = path.join(dashboardDir, fileName);
      const source = await readFile(filePath, "utf8");
      return `// ${fileName}\n${stripModuleSyntax(source)}`;
    }),
  );

  const bundle = `// Generated by scripts/build-effort-dashboard-bundle.mjs
// This file is intentionally non-module so the dashboard also works via file://

${parts.join("\n\n")}
`;

  await writeFile(path.join(dashboardDir, "app.bundle.js"), bundle, "utf8");
  console.log("app.bundle.js gerado com sucesso.");
}

buildBundle().catch((error) => {
  console.error("Falha ao gerar app.bundle.js:", error);
  process.exitCode = 1;
});
